INSERT INTO spot_faqs (spot_id, question, answer, sort_order) VALUES ((SELECT id FROM spots WHERE slug = 'caretta-shiodome-sky-view'), 'カレッタ汐留の展望台への行き方を教えて下さい。', 'B2Fにある直通シャトルエレベーターに乗ると46Fまで上がることができます。', 1);
