  'https://nightscape.tokyo/wp-content/uploads/2023/02/towerha-ll-funabori-mt-fuji-01.jpg',
  true,
  '2023-02-26T23:07:21+09:00',
  '2023-02-26T23:07:21+09:00',
  '2026-01-27T09:01:45+09:00'
);

