INSERT INTO spot_faqs (spot_id, question, answer, sort_order) VALUES ((SELECT id FROM spots WHERE slug = 'sakuradamon-gate'), '皇居外苑石垣ライトアップは何時から実施されますか？', '日没から21時までライトアップが実施されています。', 1);
