INSERT INTO spot_faqs (spot_id, question, answer, sort_order) VALUES ((SELECT id FROM spots WHERE slug = 'tatsumisakura-bridge'), '辰巳桜橋がロケ地に使われたドラマのタイトルは？', 'おっさんずラブ、3千円の使い方、階段下のゴッホなど多数のドラマロケ地に使われています。', 1);
