INSERT INTO spot_faqs (spot_id, question, answer, sort_order) VALUES ((SELECT id FROM spots WHERE slug = 'interconti-tokyo-bay'), '築地大橋や勝鬨橋のライトアップは何時まで実施されていますか？', '築地大橋や勝鬨橋のライトアップは日没から23時まで実施されています。', 1);
