INSERT INTO spot_faqs (spot_id, question, answer, sort_order) VALUES ((SELECT id FROM spots WHERE slug = 'aquacity-odaiba'), 'レインボーブリッジのライトアップは何時まで実施されていますか？', 'レインボーブリッジは日没から24:00までライトアップが実施されています。', 1);
