INSERT INTO spot_faqs (spot_id, question, answer, sort_order) VALUES ((SELECT id FROM spots WHERE slug = 'marine-tower'), '横浜マリンタワー展望台のデイチケットの入場可能時間はいつまで？', '10:00~18:00となっています（最終入場時刻は17:30）', 4);
