INSERT INTO spot_faqs (spot_id, question, answer, sort_order) VALUES ((SELECT id FROM spots WHERE slug = 'chidorigabuchi'), '2025年の千鳥ヶ淵夜桜ライトアップはいつまで実施されていますか？', '2025年3月28日（金）～4月8日（火） まで実施されています。', 0);
