-- Post: 音無親水公園 夜桜のライトアップ 2025 (otonashigawa-park)
INSERT INTO spots (
  slug, title, type, category_id, content,
  name, lead, report, address,
  official_url, official_label, sns_url, sns_label,
  relation_url, relation_label,
