  NULL,
  null,
  null,
  3.6,
  3.5,
  4,
  3.8,
  'https://nightscape.tokyo/wp-content/uploads/2025/12/asakusa-11.jpg',
  true,
  '2025-12-29T00:48:21+09:00',
  '2025-12-29T00:48:21+09:00',
